// 🔄 synchronisation Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

const storeDefault = "default";
const storeFile = "file";

// Supprimer enrichedVars du stockage par défaut
global.set("enrichedVars", undefined, storeDefault);

// Récupération des variables globales du stockage par défaut
const allKeys = global.keys(storeDefault) || [];
let globalVars = {};
allKeys.forEach(key => {
    if (key !== "enrichedVars") {
        const val = global.get(key, storeDefault);
        globalVars[key] = (typeof val === "object") ? JSON.parse(JSON.stringify(val)) : val;
    }
});

// Chargement de enrichedVars depuis le stockage fichier
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 🔄 Conversion utile (string => typed)
function convertFromString(value, type) {
    if (value === null || value === undefined) return defaultForType(type);
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        return defaultForType(type);
    }
}

// 🔄 Conversion utile (typed => string ou JSON)
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            default:
                return String(value);
        }
    } catch (err) {
        return String(value);
    }
}

// 🧠 Traitement des variables globales existantes
Object.keys(globalVars).forEach(key => {
    const val = globalVars[key];
    const type = typeof val;
    if (enrichedVars[key] && enrichedVars[key].instances && enrichedVars[key].proprietesByInstance) {
        const { instances, proprietesByInstance } = enrichedVars[key];
        const { proprietes } = proprietesByInstance;

        // Initialiser les schémas pour les objets
        proprietes.forEach(p => {
            if (p.type === "object" && !p.schema) {
                p.schema = {};
            }
        });

        instances.forEach(instance => {
            if (!proprietesByInstance.valeurs) proprietesByInstance.valeurs = {};
            if (!proprietesByInstance.valeurs[instance]) proprietesByInstance.valeurs[instance] = {};
            proprietes.forEach(prop => {
                const propName = prop.nom;
                const propType = prop.type;
                const sourceValue = val?.[instance]?.[propName];
                if (sourceValue !== undefined) {
                    proprietesByInstance.valeurs[instance][propName] = convertFromString(sourceValue, propType);
                } else {
                    proprietesByInstance.valeurs[instance][propName] = defaultForType(propType);
                }
            });
            // Gérer les abbrProprietes
            if (val._abbrProprietes) {
                proprietes.forEach(prop => {
                    if (val._abbrProprietes[prop.nom]) prop.abbr = val._abbrProprietes[prop.nom];
                });
            }
        });

        // Gérer abbrVarG et indexInstances
        if (val._abbrVarG) enrichedVars[key].abbrVarG = val._abbrVarG;
        if (val._indexInstances) enrichedVars[key].indexInstances = val._indexInstances;
    } else {
        // Variable simple (pas d’instance)
        if (!enrichedVars[key]) {
            enrichedVars[key] = {
                nomVarG: key,
                typeVarG: type,
                instances: ["*"],
                descriptionVarG: "",
                dateUpdateVarG: new Date().toISOString(),
                proprietesByInstance: {
                    proprietes: [{ nom: "*", type }],
                    valeurs: {
                        "*": {
                            "*": convertFromString(val, type)
                        }
                    }
                }
            };
        } else {
            // Met à jour valeur simple
            enrichedVars[key].proprietesByInstance.valeurs = {
                "*": {
                    "*": convertFromString(val, type)
                }
            };
        }
        if (val._abbrVarG) enrichedVars[key].abbrVarG = val._abbrVarG;
        if (val._indexInstances) enrichedVars[key].indexInstances = val._indexInstances;
    }
});

// 🧠 Variables manquantes à restaurer dans default
Object.keys(enrichedVars).forEach(key => {
    if (!globalVars.hasOwnProperty(key)) {
        const e = enrichedVars[key];
        const instances = e.instances || [];
        const props = e.proprietesByInstance?.proprietes || [];
        const valeurs = e.proprietesByInstance?.valeurs || {};
        let result = {};
        instances.forEach(instance => {
            result[instance] = {};
            props.forEach(prop => {
                const name = prop.nom;
                const type = prop.type;
                const value = valeurs?.[instance]?.[name];
                result[instance][name] = convertFromString(value, type);
            });
            // Restaurer abbrProprietes côté mémoire
            if (props.some(p => p.abbr)) {
                result[instance]._abbrProprietes = {};
                props.forEach(p => {
                    if (p.abbr) result[instance]._abbrProprietes[p.nom] = p.abbr;
                });
            }
        });
        // Restaurer abbrVarG et indexInstances côté mémoire
        if (e.abbrVarG) result._abbrVarG = e.abbrVarG;
        if (e.indexInstances) result._indexInstances = e.indexInstances;
        // S’il n’y a qu’une instance "*", on peut aplatir
        if (instances.length === 1 && instances[0] === "*") {
            global.set(key, result["*"], storeDefault);
        } else {
            global.set(key, result, storeDefault);
        }
    }
});

// 💾 Enregistrer enrichedVars corrigé
global.set("enrichedVars", enrichedVars, storeFile);
msg.payload = enrichedVars;
msg.info = "✅ Synchronisation enrichedVars complète terminée.";
return msg;

