// 🔄 fonction initialisationViaEnrichedVars,  Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// Stores utilisés
const storeDefault = "default";
const storeFile = "file";

// 1️⃣ - Nettoyer toutes les variables du store "default"
(global.keys(storeDefault) || []).forEach(k => {
    global.set(k, undefined, storeDefault);
});

// 2️⃣ - Récupérer enrichedVars depuis le fichier
let enrichedVars = global.get("enrichedVars", storeFile) || {};
node.warn("Données chargées depuis le fichier : " + JSON.stringify(enrichedVars));

// 3️⃣ - Conversion : string → typé
function convertFromString(value, type, defaultVal) {
    if (value === null || value === undefined) {
        if (defaultVal !== undefined) {
            return defaultVal;
        }
        return defaultForType(type);
    }
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        if (defaultVal !== undefined) {
            return defaultVal;
        }
        return defaultForType(type);  // Valeur par défaut en cas d'erreur
    }
}

// 4️⃣ - Restaurer toutes les variables dans le store "default"
Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || ["*"];
    const props = e.proprietesByInstance?.proprietes || [];
    const valeurs = e.proprietesByInstance?.valeurs || {};
    let variable = {};

    // Initialiser les valeurs par défaut pour les propriétés
    props.forEach(p => {
        if (p.type === "object" && !p.defaultVal) {
            p.defaultVal = {};
        }
    });

    // Remplissage des instances
    instances.forEach(instance => {
        variable[instance] = {};
        props.forEach(prop => {
            const name = prop.nom;
            const type = prop.type;
            const rawValue = valeurs?.[instance]?.[name];
            const defaultVal = prop.defaultVal;

            // Gestion des valeurs par défaut pour les objets
            if (type === "object" && defaultVal) {
                if (rawValue === undefined) {
                    variable[instance][name] = JSON.parse(JSON.stringify(defaultVal));
                } else {
                    variable[instance][name] = convertFromString(rawValue, type, defaultVal);
                }
            } else {
                variable[instance][name] = convertFromString(rawValue, type, defaultVal?.default);
            }

            if (prop.abbr) {
                if (!variable._abbrProprietes) variable._abbrProprietes = {};
                variable._abbrProprietes[name] = prop.abbr;
            }
        });
    });

    // Ajout des métadonnées globales
    if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
    if (e.indexInstances) variable._indexInstances = e.indexInstances;

    // Sauvegarde dans memoryOnly
    if (instances.length === 1 && instances[0] === "*") {
        global.set(key, variable["*"], storeDefault);
    } else {
        global.set(key, variable, storeDefault);
    }
});

// 5️⃣ - Fin
msg.payload = enrichedVars;
msg.info = "✅ Initialisation enrichie depuis enrichedVars (file) terminée.";
return msg;

//function sauvVarGlobalInFile sauvegarde les variables du store default -> enrichedVars (file)
function defaultForType(type) {
  switch(type) {
    case "boolean": return false;
    case "int": case "number": return 0;
    case "array": return [];
    case "object": return {};
    case "date": return new Date().toISOString().slice(0,10);
    default: return "";
  }
}
const storeDefault = "default";
const allKeys = global.keys(storeDefault) || [];
let enrichedVars = global.get("enrichedVars", "file") || {};

function serializeForStore(value) {
  if (value === null || value === undefined) return "";
  if (Array.isArray(value) || typeof value === "object") return JSON.stringify(value);
  if (typeof value === "boolean") return value ? "true" : "false";
  return String(value);
}

allKeys.forEach(key => {
  if (key === "enrichedVars") return;
  const val = global.get(key, storeDefault);
  if (val === undefined) return;

  // si objet d'instances
  if (val && typeof val === "object" && !Array.isArray(val)) {
    const instances = Object.keys(val);
    if (instances.length === 0) return;
    const first = val[instances[0]];

    // si first est objet -> propriétés
    if (first && typeof first === "object") {
      const props = Object.keys(first);
      const propDefs = props.map(p => {
        const v = first[p];
        const t = Array.isArray(v) ? "array" : typeof v;
        return { nom:p, type:t, schema: (t==="object")?{}:null };
      });
      const valeurs = {};
      instances.forEach(inst => {
        valeurs[inst] = {};
        propDefs.forEach(({nom,type}) => {
          const v = val[inst]?.[nom];
          valeurs[inst][nom] = (type==="object"||type==="array") ? JSON.stringify(v) : serializeForStore(v);
        });
      });
      enrichedVars[key] = {
        nomVarG: key,
        abbrVarG: val._abbrVarG || "",
        typeVarG: "object",
        instances,
        descriptionVarG: "Auto-export",
        dateUpdateVarG: new Date().toISOString(),
        indexInstances: instances.map((_,i)=>String(i)).join(","),
        proprietesByInstance: {
          proprietes: propDefs,
          valeurs,
          abbrProprietes: val._abbrProprietes || {}
        }
      };
    } else {
      // cas valeur simple
      enrichedVars[key] = {
        nomVarG: key,
        abbrVarG: val._abbrVarG || "",
        typeVarG: typeof val,
        instances: ["*"],
        descriptionVarG: "Auto-export",
        dateUpdateVarG: new Date().toISOString(),
        proprietesByInstance: {
          proprietes: [{ nom:"*", type: typeof val }],
          valeurs: { "*": { "*": serializeForStore(val) } },
          abbrProprietes: val._abbrProprietes || {}
        }
      };
    }
  } else {
    // autres cas : simple
    enrichedVars[key] = {
      nomVarG: key,
      abbrVarG: "",
      typeVarG: typeof val,
      instances: ["*"],
      descriptionVarG: "Auto-export",
      dateUpdateVarG: new Date().toISOString(),
      proprietesByInstance: {
        proprietes: [{ nom:"*", type: typeof val }],
        valeurs: { "*": { "*": serializeForStore(val) } },
        abbrProprietes: {}
      }
    };
  }
});

global.set("enrichedVars", enrichedVars, "file");
msg.payload = enrichedVars;
msg.info = "💾 Sauvegarde vers enrichedVars (file) terminée.";
return msg;

//function prepareTableauVars
let enrichedVars = global.get("enrichedVars", "file") || {};
console.log("Données chargées depuis global.json :", enrichedVars);

let tableauPourUI = [];
flow.set("varSelected", "");

Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;  // Ignore les entrées invalides

    let props = [];
    let proprieteResume = "(Aucune propriété définie)";

    // Vérifie si la structure contient `proprietes` ou `proprietesByInstance`
    if (e.proprietes) {
        props = e.proprietes;
        proprieteResume = props.length > 0
            ? props.map(p => `${p.nom} (${p.type})`).join(", ")
            : "(Aucune propriété définie)";
    } else if (e.proprietesByInstance && e.proprietesByInstance.proprietes) {
        props = e.proprietesByInstance.proprietes;
        proprieteResume = props.length > 0
            ? props.map(p => `${p.nom} (${p.type})`).join(", ")
            : "(Aucune propriété définie)";
    }

    const instances = e.instances || ["*"];

    tableauPourUI.push({
        nomVarG,
        typeVarG: e.typeVarG || "object",
        abbrVarG: e.abbrVarG || "",
        instances: instances.join(", "),
        proprietes: proprieteResume,
        description: e.descriptionVarG || ""
    });
});

msg.payload = tableauPourUI;
return msg;

// function recupVarSelected
let varSelected = null;

// 1) Charger la liste des variables existantes
let enrichedVars = global.get("enrichedVars", "file") || {};
let listeVars = Object.keys(enrichedVars);

// 2) Cas bouton "AjouterUneVarG"
if (msg.topic === "newVarG") {
    varSelected = "new";
    msg.topic = "newVarG";  // (optionnel)
}
// 3) Cas sélection depuis la table
else {
    varSelected = msg.payload?.row?.nomVarG || msg.payload?.nomVarG || null;
}

// 4) Vérification si aucune sélection
if (!varSelected) {
    if (listeVars.length === 0) {
        msg.info = "⚠️ Aucune variable existante dans enrichedVars.";
    } else {
        msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
    }
    return msg; // on arrête ici
}

// 5) Stocker la variable sélectionnée dans le flow
flow.set("varSelected", varSelected);

// 6) Construire le message d’info
if (varSelected === "new") {
    msg.info = "➕ Création d’une nouvelle variable.";
} else {
    msg.info = `✅ Vous êtes sur la variable : ${varSelected}`;
}

// 7) Retourner le résultat
msg.payload = varSelected;
return msg;

// function prepareFormVarSelected 
let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;

// Cas création d’une nouvelle variable (via bouton "AjouterUneVarG")
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: "*",
        descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.topic = "newVarG";
}
// Cas édition d’une variable existante sélectionnée
else if (varSelected && enrichedVars[varSelected]) {
    const selected = enrichedVars[varSelected];
    msg.payload = {
        nomVarG: selected.nomVarG || "",
        abbrVarG: selected.abbrVarG || "",
        instances: selected.instances ? selected.instances.join(", ") : "",
        descriptionVarG: selected.descriptionVarG || "",
        dateUpdateVarG: selected.dateUpdateVarG || new Date().toISOString()
    };
}
// Cas où aucune variable n’est sélectionnée
else {
    if (Object.keys(enrichedVars).length === 0) {
        msg.info = "⚠️ Aucune variable définie dans enrichedVars. Utilisez 'AjouterUneVarG' pour commencer.";
    } else {
        msg.info = "⚠️ Aucune variable sélectionnée pour édition.";
    }

    // Payload neutre → évite le crash du formulaire
    msg.payload = {
        nomVarG: "",
        abbrVarG: "",
        instances: "",
        descriptionVarG: "",
        dateUpdateVarG: new Date().toISOString()
    };

    return msg; // on stoppe ici pour éviter d'aller plus loin
}

return msg;

//function sauvVarSelected
let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;
let formData = msg.payload;

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Formulaire incomplet ou variable non spécifiée.";
    return null;
}

// --- Normalisation du nom ---
let newName = formData.nomVarG.trim();

// Vérification caractères autorisés (A-Z, a-z, 0-9, _)
if (!/^[A-Za-z0-9_]+$/.test(newName)) {
    msg.info = `❌ Nom de variable invalide ('${newName}'). Utilise uniquement lettres, chiffres ou '_'`;
    return null;
}

let oldName = varSelected;

// --- Cas création ---
if (!enrichedVars[oldName]) {
    if (enrichedVars[newName]) {
        msg.info = `❌ Impossible de créer '${newName}', une variable existe déjà avec ce nom.`;
        return null;
    }

    enrichedVars[newName] = {
        nomVarG: newName,
        abbrVarG: formData.abbrVarG || "",
        instances: formData.instances
            ? formData.instances.split(",").map(e => e.trim())
            : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: []
    };

    flow.set("varSelected", newName);
    global.set("enrichedVars", enrichedVars, "file");

    msg.payload = newName;
    msg.info = `✅ Nouvelle variable créée : ${newName}`;
    return msg;
}

// --- Cas modification ---
let current = enrichedVars[oldName];

// Si le nom change
if (oldName !== newName) {
    if (enrichedVars[newName]) {
        msg.info = `⚠️ '${newName}' existe déjà, impossible de renommer '${oldName}'`;
        return null;
    }

    enrichedVars[newName] = current;
    delete enrichedVars[oldName];
    flow.set("varSelected", newName);
}

// Instances actuelles et nouvelles
let newInstances = formData.instances
    ? formData.instances.split(",").map(e => e.trim())
    : current.instances;

let oldInstances = current.instances || [];

// Synchronisation des propriétés
(current.proprietes || []).forEach(prop => {
    prop.valeurs = prop.valeurs || {};

    // Ajouter les nouvelles instances avec valeur par défaut
    newInstances.forEach(inst => {
        if (!(inst in prop.valeurs)) {
            // valeur par défaut dépend du type
            switch (prop.type) {
                case "boolean":
                    prop.valeurs[inst] = false;
                    break;
                case "int":
                case "number":
                    prop.valeurs[inst] = 0;
                    break;
                case "array":
                    prop.valeurs[inst] = [];
                    break;
                case "object":
                    prop.valeurs[inst] = {};
                    break;
                case "date":
                    prop.valeurs[inst] = new Date().toISOString().slice(0, 10);
                    break;
                default:
                    prop.valeurs[inst] = "";
            }
        }
    });

    // Supprimer les valeurs des instances disparues
    oldInstances.forEach(inst => {
        if (!newInstances.includes(inst)) {
            delete prop.valeurs[inst];
        }
    });
});

// Mise à jour de la variable
enrichedVars[newName || oldName] = {
    ...enrichedVars[newName || oldName],
    nomVarG: newName,
    abbrVarG: formData.abbrVarG || enrichedVars[newName || oldName].abbrVarG,
    instances: newInstances,
    descriptionVarG:
        formData.descriptionVarG ||
        enrichedVars[newName || oldName].descriptionVarG,
    dateUpdateVarG: new Date().toISOString()
};

global.set("enrichedVars", enrichedVars, "file");

msg.payload = newName || oldName;
msg.info = `✅ Variable ${
    oldName !== newName ? `renommée de '${oldName}' en '${newName}' et ` : ""
}mise à jour.`;
return msg;

// function : supprimerVarG
if (msg.payload === "confirm_clicked") {
  const varSelected = flow.get("varSelected");
  if (!varSelected) {
    msg.info = "⚠️ Rien à supprimer.";
    return msg;
  }
  let enrichedVars = global.get("enrichedVars", "file") || {};
  delete enrichedVars[varSelected];
  delete enrichedVars[""];//supprime var fantome
  global.set("enrichedVars", enrichedVars, "file");
  global.set(varSelected, undefined, "default");
  flow.set("varSelected", "none");
  msg.payload = "none";
  msg.info = `✅ Variable "${varSelected}" supprimée.`;
}
return msg;

const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.info = "⚠️ Aucune variable sélectionnée à supprimer.";
    return msg;
}

// Préparer un message pour ui-dialog
msg.payload = {
    title: "⚠️ Confirmation suppression",
    message: `Voulez-vous vraiment supprimer la variable "${varSelected}" ?`,
    buttons: [
        { label: "❌ Annuler", value: "cancel" },
        { label: "✅ Supprimer", value: "confirm", class: "red" }
    ]
};
return msg;

// === saveSchemaOrRow ===
// Sauvegarde cohérente d’une propriété (ajout ou édition) 
// Ne touche PAS à la liste des instances (gérée par Form_Var_Modif)

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected");

if (!varSelected || !enrichedVars[varSelected]) {
    node.warn("❌ Aucune variable sélectionnée pour sauvegarde propriété.");
    return null;
}

// Récupération de la variable concernée
let currentVar = enrichedVars[varSelected];

// Normalisation : s’assurer que proprietes existe
if (!Array.isArray(currentVar.proprietes)) {
    currentVar.proprietes = [];
}

// Données venant du formulaire (Form Edit Prop ou Schéma)
let form = msg.payload;
if (!form || !form.nom) {
    node.warn("❌ Propriété invalide ou incomplète");
    return null;
}

// Construction de la propriété normalisée
let newProp = {
    nom: form.nom,
    abbr: form.abbr || "",
    type: form.type || "string",
    schema: form.schema || null,
    valeurs: {}
};

// Initialisation des valeurs pour CHAQUE instance existante
(currentVar.instances || ["*"]).forEach(inst => {
    if (form.instanceValues && form.instanceValues[inst] !== undefined) {
        // On garde la valeur transmise si dispo
        newProp.valeurs[inst] = form.instanceValues[inst];
    } else if (form.defaut !== undefined && form.defaut !== null) {
        // Sinon on copie la valeur défaut
        newProp.valeurs[inst] = form.defaut;
    } else {
        // Sinon fallback en fonction du type
        switch (newProp.type) {
            case "boolean": newProp.valeurs[inst] = false; break;
            case "int":
            case "number": newProp.valeurs[inst] = 0; break;
            case "array": newProp.valeurs[inst] = []; break;
            case "object": newProp.valeurs[inst] = {}; break;
            case "date": newProp.valeurs[inst] = new Date().toISOString(); break;
            default: newProp.valeurs[inst] = "";
        }
    }
});

// Recherche si la propriété existe déjà
let idx = currentVar.proprietes.findIndex(p => p.nom === newProp.nom);

if (idx >= 0) {
    // --- Mise à jour d’une propriété existante ---
    currentVar.proprietes[idx] = newProp;
    msg.info = `✅ Propriété '${newProp.nom}' mise à jour pour '${varSelected}'.`;
} else {
    // --- Ajout d’une nouvelle propriété ---
    currentVar.proprietes.push(newProp);
    msg.info = `✅ Nouvelle propriété '${newProp.nom}' ajoutée à '${varSelected}'.`;
}

// Mise à jour date
currentVar.dateUpdateVarG = new Date().toISOString();

// Sauvegarde globale
enrichedVars[varSelected] = currentVar;
global.set("enrichedVars", enrichedVars, "file");

// Renvoi du contenu mis à jour
msg.payload = currentVar;
msg.topic = "savePropertyDone";
return msg;

// prepareTable (version robuste pour FlowFuse ui-table - Dashboard2)
// Lit global.enrichedVars (file) et flow.varSelected,
// construit msg.ui_control.columns et msg.payload (array of rows).

let enriched = global.get("enrichedVars","file") || {};
let varSelected = flow.get("varSelected") || null;

node.warn("prepareTable -> varSelected = " + String(varSelected));

if (!varSelected || !enriched[varSelected]) {
  msg.payload = [];
  msg.info = "⚠️ Aucune variable sélectionnée / variable introuvable.";
  return msg;
}

let V = enriched[varSelected];
let instances = Array.isArray(V.instances) && V.instances.length ? V.instances.slice() : ["*"];

// Colonnes : nom, abbr, type, defaut, puis une colonne par instance, puis actions
let cols = [
  { field: "nom", title: "Nom propriété" },
  { field: "abbr", title: "Abbr" },
  { field: "type", title: "Type" },
  { field: "defaut", title: "Valeur défaut (JSON)" }
];
instances.forEach(inst => {
  cols.push({ field: "inst_" + inst, title: inst });
});
// Colonne action = bouton (formatter button)
cols.push({
  field: "edit",
  title: "Actions",
  formatter: "button",
  formatterParams: { label: "✏️ Edit" }
});

// Envoyer les colonnes dynamiquement au ui-table
msg.ui_control = {
  columns: cols,
  options: {
    layout: "fitData",
    rowHeight: 36,
    resizableColumns: true
  }
};

// Construire les lignes : forcer tout en string lisible (JSON pour objets/arrays)
let rows = (V.proprietes || []).map(p => {
  const row = {
    _propName: p.nom,
    nom: p.nom,
    abbr: p.abbr || "",
    type: p.type || ""
  };

  // valeur par défaut : priorité prop.valeurs["*"] sinon prop.defaut
  let defaultVal = (p.valeurs && p.valeurs["*"] !== undefined) ? p.valeurs["*"]
                  : (p.defaut !== undefined ? p.defaut : null);

  row.defaut = (defaultVal === null || defaultVal === undefined)
                ? ""
                : (typeof defaultVal === "object" ? JSON.stringify(defaultVal) : String(defaultVal));

  // valeurs par instance
  instances.forEach(inst => {
    let v;
    if (p.valeurs && p.valeurs[inst] !== undefined) v = p.valeurs[inst];
    else v = "*"; // hérite du défaut

    row["inst_" + inst] = (v === "*" ? "*" : (typeof v === "object" ? JSON.stringify(v) : String(v)));
  });

  // valeur arbitraire pour activer le bouton
  row.edit = "edit";
  return row;
});

msg.payload = rows;
msg.info = `ℹ️ Variable : ${V.nomVarG || varSelected} — ${rows.length} propriété(ies) — instances: ${instances.join(",")}`;

return msg;

// On ne traite que les clics sur bouton "edit"
if (msg.topic !== "editProperty" || !msg.payload) {
    return null;
}

let row = msg.payload;

// Préparer le message attendu par ton ui-form
msg.topic = "editProperty";
msg.payload = {
    nom: row.nom || row._propName || "",
    abbr: row.abbr || "",
    type: row.type || "string",
    defaut: row.defaut !== undefined ? row.defaut : ""
};

return msg;

// === deleteProperty ===
// Supprime une propriété d’une variable enrichie
// ⚠️ Ne touche PAS aux instances (gérées par Form_Var_Modif)

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected");

if (!varSelected || !enrichedVars[varSelected]) {
    node.warn("❌ Aucune variable sélectionnée pour suppression propriété.");
    return null;
}

// Récupération de la variable courante
let currentVar = enrichedVars[varSelected];

// Normalisation
if (!Array.isArray(currentVar.proprietes)) {
    currentVar.proprietes = [];
}

// Nom de la propriété à supprimer
let propName = msg.payload?.propName || msg.payload?.nom;
if (!propName) {
    node.warn("❌ Aucun nom de propriété fourni pour suppression.");
    return null;
}

// Recherche de la propriété
let idx = currentVar.proprietes.findIndex(p => p.nom === propName);

if (idx >= 0) {
    // Suppression
    currentVar.proprietes.splice(idx, 1);
    msg.info = `🗑️ Propriété '${propName}' supprimée de '${varSelected}'.`;
} else {
    msg.info = `⚠️ Propriété '${propName}' introuvable dans '${varSelected}'.`;
}

// Mise à jour de la date
currentVar.dateUpdateVarG = new Date().toISOString();

// Sauvegarde globale
enrichedVars[varSelected] = currentVar;
global.set("enrichedVars", enrichedVars, "file");

// Renvoi du contenu mis à jour
msg.payload = currentVar;
msg.topic = "deletePropertyDone";
return msg;
